{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a combinatorial optimization problem involving placing 3x3 stamps on a 9x9 grid to maximize a sum modulo 998244353. Since the board is small (9x9) and the number of stamps is limited (K=81), but the objective is a modulo sum, this is likely a search or dynamic programming problem. However, the modulo operation makes standard greedy or local search approaches tricky because a large sum can become small after the modulo. I will break this into grid representation, state space exploration, and the final optimization logic.",
  "helpers": [
    {
      "label": "grid_generator",
      "instructions": "Generate all possible 3x3 stamp placement coordinates on a 9x9 board. A placement is defined by its top-left corner (r, c) where 0 <= r <= 6 and 0 <= c <= 6. Represent each placement as a set of 9 cell indices."
    },
    {
      "label": "objective_calculator",
      "instructions": "Given a 9x9 board of integers and a subset of up to 81 stamp placements, calculate the sum of all cell values after applying the stamps, then return that sum modulo 998244353. Note: Applying a stamp means adding its value to the cells it covers."
    },
    {
      "label": "optimization_engine",
      "instructions": "Given the list of all possible 3x3 stamp placements and the 9x9 board values, find a subset of up to 81 placements that maximizes the total sum of the board entries modulo 998244353. Since the modulo is large and the board is small, evaluate if the maximum sum without modulo is significantly larger than the modulo, or if the modulo operation requires a specific search strategy like backtracking or bitmask DP."
    }
  ],
  "synthesis_brief": "The parent will take the list of valid 3x3 placement coordinates from grid_generator, use the objective_calculator to evaluate potential configurations, and use the optimization_engine to find the subset of placements that yields the highest value modulo 998244353."
}

